// ── Impression tracking helpers ──
function sendTrackingEventToOptimizely(eventName) {
  window.optimizely = window.optimizely || [];
  window.optimizely.push({
    type: 'event',
    eventName: eventName,
  });
}

function createIntersectionObserver(callback, options) {
  var hasIntersectionObserver =
    typeof window !== 'undefined' &&
    'IntersectionObserver' in window &&
    'IntersectionObserverEntry' in window &&
    'intersectionRatio' in window.IntersectionObserverEntry.prototype;

  return hasIntersectionObserver ? new window.IntersectionObserver(callback, options || {}) : undefined;
}

function setIntersectionObservers(intersectionPointElement, intersectionCallback) {
  if (!intersectionPointElement || typeof intersectionCallback !== 'function') {
    throw new Error(
      !intersectionPointElement ? 'No element has been provided for Intersection Observer': 'intersectionCallback is not a function'
    );
  }
  var observer = createIntersectionObserver(function (entries) {
    if (!entries) return;
    entries.forEach(function (entry) {
      if (entry.isIntersecting) {
        intersectionCallback();
        observer.unobserve(entry.target);
      }
    });
  });
  if (observer) {
    observer.observe(intersectionPointElement);
  }
  return observer;
}

