var impressionEventName = 'mini-cta-visible';

utils.waitForElement('#LP_DIV_TRAVEL_1239001').then(function(element) {
    console.log('LP Travel div found (shared)');

    // Track impression when the whole component is visible
    setIntersectionObservers(element.parentElement, function () {
      sendTrackingEventToOptimizely(impressionEventName);
      console.log('Impression tracked for', impressionEventName);
    });

    // Track impression when the fallback call button is visible
    var fallBackCallButton = document.querySelector('a[data-testid="travel-call-button"]');
    if (fallBackCallButton) {
      setIntersectionObservers(fallBackCallButton, function () {
        sendTrackingEventToOptimizely('fallback-button-visible');
        console.log('Impression tracked for fallback-button-visible');
      });
    }
  
    var chatUnavailable = document.querySelector('a[data-testid="travel-chat-unavailable"]');
  	if (chatUnavailable) {
      setIntersectionObservers(chatUnavailable, function () {
        sendTrackingEventToOptimizely('chat-unavailable-visible');
        console.log('Impression tracked for chat-unavailable-visible');
      });
    }
});
