const waitUntil = (condition, wait = 10000) => {
	return new Promise((resolve, reject) => {
		let stop;

		const timeout =
		wait &&
		setTimeout(() => {
			stop = true;
			reject();
		}, wait);

		const check = () => {
			if (stop) return;
			if (!condition()) return requestAnimationFrame(check);

			clearTimeout(timeout);
			resolve(condition());
		};

		requestAnimationFrame(check);
	});
};

